import sys

class Solution:
    def push(self, x: int, stackNewestOnTop: list[int], stackOldestOnTop: list[int]) -> None:
        stackNewestOnTop.append(x)

    def pop(self, stackNewestOnTop: list[int], stackOldestOnTop: list[int]) -> int:
        if not stackOldestOnTop:
            while stackNewestOnTop:
                stackOldestOnTop.append(stackNewestOnTop.pop())
        return stackOldestOnTop.pop() if stackOldestOnTop else -1

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
        stackNewestOnTop = []
        stackOldestOnTop = []
        sol = Solution()
        for _ in range(n):
            op = next(it)
            if op == 'push':
                x = int(next(it))
                sol.push(x, stackNewestOnTop, stackOldestOnTop)
            elif op == 'pop':
                print(sol.pop(stackNewestOnTop, stackOldestOnTop))
    except StopIteration:
        sys.exit(0)

