#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    void push(int x, stack<int>& stackNewestOnTop, stack<int>& stackOldestOnTop) {
        stackNewestOnTop.push(x);
    }

    int pop(stack<int>& stackNewestOnTop, stack<int>& stackOldestOnTop) {
        if (stackOldestOnTop.empty()) {
            while (!stackNewestOnTop.empty()) {
                stackOldestOnTop.push(stackNewestOnTop.top());
                stackNewestOnTop.pop();
            }
        }
        if (!stackOldestOnTop.empty()) {
            int res = stackOldestOnTop.top();
            stackOldestOnTop.pop();
            return res;
        }
        return -1;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    stack<int> stackNewestOnTop;
    stack<int> stackOldestOnTop;
    Solution sol;
    for (int i = 0; i < n; i++) {
        string op;
        if (!(cin >> op)) return 0;
        if (op == "push") {
            int x;
            if (!(cin >> x)) return 0;
            sol.push(x, stackNewestOnTop, stackOldestOnTop);
        } else if (op == "pop") {
            cout << sol.pop(stackNewestOnTop, stackOldestOnTop) << "\n";
        }
    }
    return 0;
}
